// --- Logout Endpoint ---
app.post('/logout', (req, res) => {
  const rememberCookie = req.cookies[REMEMBER_ME_COOKIE_NAME];

  if (rememberCookie) {
    try {
      const decoded = Buffer.from(rememberCookie, 'base64').toString('utf-8');
      const { username } = JSON.parse(decoded);

      // Invalidate all remember-me tokens for this user
      if (username && rememberTokensDB[username]) {
        delete rememberTokensDB[username];
        console.log(`Cleared all remember-me tokens for user: ${username}`);
      }
    } catch (err) {
      // Ignore parse errors during logout
    }
  }

  clearRememberMeCookie(res);
  req.user = null;

  res.json({ message: 'Logged out successfully. Remember Me cookie cleared.' });
});

